(function(){"use strict";function S(q,L,w=100,r=60){const c=q.filter(t=>!t.parentId);if(c.length===0)return new Map;const h=new Map(c.map(t=>[t.id,t])),u=new Map,M=new Map;for(const t of c)u.set(t.id,new Set),M.set(t.id,new Set);for(const t of L)h.has(t.source)&&h.has(t.target)&&t.source!==t.target&&(u.get(t.source).add(t.target),M.get(t.target).add(t.source));const o=new Map;for(const t of c)o.set(t.id,M.get(t.id).size);const e=new Map,s=[];for(const t of c)o.get(t.id)===0&&(e.set(t.id,0),s.push(t.id));if(s.length===0){let t=1/0,n=c[0].id;for(const a of c){const x=o.get(a.id);x<t&&(t=x,n=a.id)}e.set(n,0),s.push(n)}const g=new Map(o);let d=0;for(;d<s.length;){const t=s[d++],n=e.get(t);for(const a of u.get(t)){(e.get(a)??-1)<n+1&&e.set(a,n+1);const x=g.get(a)-1;g.set(a,x),x===0&&s.push(a)}}for(const t of c)e.has(t.id)||e.set(t.id,0);const i=Math.max(...e.values()),l=Array.from({length:i+1},()=>[]);for(const[t,n]of e)l[n].push(t);const p=(t,n)=>{const a=t.indexOf(n);return a>=0?a:t.length/2};for(let t=0;t<2;t++){for(let n=1;n<=i;n++){const a=l[n-1];l[n].sort((x,k)=>{const y=[...M.get(x)].filter(f=>e.get(f)===n-1),m=[...M.get(k)].filter(f=>e.get(f)===n-1),v=y.length?y.reduce((f,E)=>f+p(a,E),0)/y.length:0,H=m.length?m.reduce((f,E)=>f+p(a,E),0)/m.length:0;return v-H})}for(let n=i-1;n>=0;n--){const a=l[n+1];l[n].sort((x,k)=>{const y=[...u.get(x)].filter(f=>e.get(f)===n+1),m=[...u.get(k)].filter(f=>e.get(f)===n+1),v=y.length?y.reduce((f,E)=>f+p(a,E),0)/y.length:0,H=m.length?m.reduce((f,E)=>f+p(a,E),0)/m.length:0;return v-H})}}const b=l.map(t=>t.reduce((n,a)=>{var x;return n+(((x=h.get(a))==null?void 0:x.height)??60)+r},0)-r),A=Math.max(...b,0),I=new Map;let B=0;for(let t=0;t<=i;t++){const n=l[t],a=Math.max(...n.map(y=>{var m;return((m=h.get(y))==null?void 0:m.width)??120}));let k=Math.round((A-b[t])/2);for(const y of n){const m=h.get(y);I.set(y,{x:B,y:k}),k+=m.height+r}B+=a+w}return I}function W(q,L,w=150){const r=q.filter(o=>!o.parentId);if(r.length===0)return new Map;const c=new Map;for(const o of r)c.set(o.id,{x:o.x+o.width/2,y:o.y+o.height/2});const h=Math.sqrt(200*200*r.length)/r.length*5;let u=h*2;for(let o=0;o<w;o++){const e=new Map;for(const s of r)e.set(s.id,{x:0,y:0});for(let s=0;s<r.length;s++)for(let g=s+1;g<r.length;g++){const d=r[s],i=r[g],l=c.get(d.id),p=c.get(i.id),b=l.x-p.x,A=l.y-p.y,I=Math.max(Math.hypot(b,A),1),B=h*h/I,t=e.get(d.id),n=e.get(i.id);t.x+=b/I*B,t.y+=A/I*B,n.x-=b/I*B,n.y-=A/I*B}for(const s of L){const g=c.get(s.source),d=c.get(s.target);if(!g||!d)continue;const i=d.x-g.x,l=d.y-g.y,p=Math.max(Math.hypot(i,l),1),b=p*p/h,A=e.get(s.source),I=e.get(s.target);A.x+=i/p*b,A.y+=l/p*b,I.x-=i/p*b,I.y-=l/p*b}for(const s of r){const g=c.get(s.id),d=e.get(s.id),i=Math.max(Math.hypot(d.x,d.y),1);g.x+=d.x/i*Math.min(i,u),g.y+=d.y/i*Math.min(i,u)}u*=.95}const M=new Map;for(const o of r){const e=c.get(o.id);M.set(o.id,{x:e.x-o.width/2,y:e.y-o.height/2})}return M}function j(q,L=40){const w=q.filter(o=>!o.parentId);if(w.length===0)return new Map;const r=Math.ceil(Math.sqrt(w.length)),c=[...w].sort((o,e)=>o.x-e.x||o.y-e.y),h=Math.max(...w.map(o=>o.width),120)+L,u=Math.max(...w.map(o=>o.height),60)+L,M=new Map;return c.forEach((o,e)=>{M.set(o.id,{x:e%r*h,y:Math.floor(e/r)*u})}),M}self.addEventListener("message",q=>{const{id:L,algorithm:w,nodes:r,edges:c,gapX:h,gapY:u,gap:M,iterations:o}=q.data;try{let e;switch(w){case"force":e=W(r,c,o??300);break;case"grid":e=j(r,M??40);break;default:e=S(r,c,h??100,u??60)}const s=[];for(const[d,i]of e)s.push({id:d,...i});const g={id:L,result:s};self.postMessage(g)}catch(e){const s={id:L,result:[],error:String(e)};self.postMessage(s)}})})();
